using sv_7b5a8e68b38747049d3c4d35b034f826.Models;

namespace sv_7b5a8e68b38747049d3c4d35b034f826.Components.Pages;

public partial class Recipes : IDisposable
{
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;

    private CancellationTokenSource? _loadCts;
    private int _lastLoadedCuisineId;

    protected override Task OnParametersSetAsync()
    {
        // Only reload when the cuisine changes, not when sort changes.
        if (CuisineId == _lastLoadedCuisineId && _recipes is not null)
        {
            return Task.CompletedTask;
        }

        return LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request before starting a new one.
        CancelPendingLoad();

        var cts = new CancellationTokenSource();
        _loadCts = cts;

        _isRefreshing = _recipes is not null;
        _errorMessage = null;
        _lastLoadedCuisineId = CuisineId;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Guard against a stale completion racing with a newer request.
            if (cts.Token.IsCancellationRequested)
            {
                return;
            }

            _recipes = result;
        }
        catch (OperationCanceledException)
        {
            // Expected when the user navigates away or switches cuisines.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null)
        {
            return [];
        }

        return string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes.OrderBy(r => r.PrepTimeMinutes)
            : _recipes.OrderByDescending(r => r.Id);
    }

    private void CancelPendingLoad()
    {
        if (_loadCts is not null)
        {
            _loadCts.Cancel();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }

    public void Dispose()
    {
        CancelPendingLoad();
    }
}

